import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

function Artisan() {
  const { id } = useParams();

  const [artisan, setArtisan] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    message: "",
  });

  useEffect(() => {
  fetch(`http://localhost:3000/api/artisans/${id}`)
    .then((res) => {
      console.log("STATUS API :", res.status);

      if (!res.ok) {
        throw new Error("Artisan introuvable");
      }

      return res.json();
    })
    .then((data) => {
      console.log("ARTISAN REÇU :", data);
      setArtisan(data);
    })
    .catch((error) => {
      console.error("ERREUR API :", error);
    });
}, [id]);

  const handleSubmit = (e) => {
    e.preventDefault();

    fetch(`http://localhost:3000/api/artisans/${id}/contact`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(formData),
    })
      .then((res) => res.json())
      .then(() => {
        alert("Message envoyé avec succès");

        setFormData({
          name: "",
          email: "",
          subject: "",
          message: "",
        });
      })
      .catch((error) => console.error(error));
  };

  if (!artisan) {
    return (
      <div className="container py-5 text-center">
        <p>Chargement...</p>
      </div>
    );
  }

  return (
    <main className="container py-5">

      {/* CARD ARTISAN */}

      <div className="card shadow border-0 mb-5">
        <div className="row g-0">

          {/* IMAGE */}

          <div className="col-12 col-md-5">
            <img
              src={artisan.image || "/images/default-artisan.jpg"}
              alt={artisan.name}
              className="img-fluid h-100 w-100 object-fit-cover rounded-start"
            />
          </div>

          {/* INFOS */}

          <div className="col-12 col-md-7">
            <div className="card-body p-4">

              <h1 className="card-title mb-4">
                {artisan.name}
              </h1>

              <p>
                <strong>Note :</strong>{" "}
                {"★".repeat(Math.round(artisan.note))}
                {"☆".repeat(5 - Math.round(artisan.note))}
              </p>

              <p>
                <strong>Spécialité :</strong>{" "}
                {artisan.specialty}
              </p>

              <p>
                <strong>Localisation :</strong>{" "}
                {artisan.location}
              </p>

              {artisan.website && (
                <p>
                  <strong>Site web :</strong>{" "}
                  <a
                    href={artisan.website}
                    target="_blank"
                    rel="noreferrer"
                  >
                    Visiter le site
                  </a>
                </p>
              )}

              <hr />

              <h2 className="h4 mb-3">
                À propos
              </h2>

              <p>
                {artisan.about}
              </p>

            </div>
          </div>
        </div>
      </div>

      {/* FORMULAIRE */}

      <div className="card shadow border-0">
        <div className="card-body p-4">

          <h2 className="mb-4">
            Contacter cet artisan
          </h2>

          <form onSubmit={handleSubmit}>

            <div className="row">

              <div className="col-12 col-md-6 mb-3">
                <label className="form-label">
                  Nom
                </label>

                <input
                  type="text"
                  name="name"
                  className="form-control"
                  value={formData.name}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="col-12 col-md-6 mb-3">
                <label className="form-label">
                  Email
                </label>

                <input
                  type="email"
                  name="email"
                  className="form-control"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
              </div>

            </div>

            <div className="mb-3">
              <label className="form-label">
                Objet
              </label>

              <input
                type="text"
                name="subject"
                className="form-control"
                value={formData.subject}
                onChange={handleChange}
                required
              />
            </div>

            <div className="mb-4">
              <label className="form-label">
                Message
              </label>

              <textarea
                name="message"
                rows="5"
                className="form-control"
                value={formData.message}
                onChange={handleChange}
                required
              ></textarea>
            </div>

            <button
              type="submit"
              className="btn btn-primary"
            >
              Envoyer le message
            </button>

          </form>
        </div>
      </div>
    </main>
  );
}

export default Artisan;
